    ['title' => 'Departments', 'value' => count($academicDepartments), 'description' => 'Academic units', 'icon' => 'fa-building-columns', 'color' => 'success'],
    ['title' => 'Upcoming Events', 'value' => sms_academic_count_local($schoolEvents, 'status', 'Upcoming'), 'description' => 'Calendar events', 'icon' => 'fa-calendar-check', 'color' => 'blue'],
];
