<script>
/* Centralized Academic Management behavior: section navigation, search, modals, and placeholders. */
(function(){
    function activate(target){document.querySelectorAll('.academic-tab').forEach(function(tab){tab.classList.toggle('active',tab.dataset.target===target);});document.querySelectorAll('.academic-panel').forEach(function(panel){panel.classList.toggle('active',panel.id===target);});var mobile=document.getElementById('mobileAcademicSelect');if(mobile){mobile.value=target;}filterRows();}
    document.querySelectorAll('.academic-tab').forEach(function(tab){tab.addEventListener('click',function(){activate(tab.dataset.target);});});
    var mobile=document.getElementById('mobileAcademicSelect');if(mobile){mobile.addEventListener('change',function(){activate(mobile.value);});}
    function currentPanel(){return document.querySelector('.academic-panel.active');}
    function filterRows(){var q=(document.getElementById('academicSearch').value||'').toLowerCase();var panel=currentPanel();if(!panel){return;}panel.querySelectorAll('tbody tr').forEach(function(row){row.style.display=!q||row.textContent.toLowerCase().indexOf(q)>-1?'':'none';});}
    document.getElementById('academicSearch').addEventListener('input',filterRows);document.getElementById('clearAcademicSearch').addEventListener('click',function(){document.getElementById('academicSearch').value='';filterRows();});
    document.querySelectorAll('.add-record,.edit-record').forEach(function(button){button.addEventListener('click',function(){var entity=button.dataset.entity||'Academic Record';document.getElementById('academicModalTitle').textContent='Add / Edit '+entity;document.getElementById('academicEntityType').value=entity;});});
    document.querySelectorAll('.delete-record').forEach(function(button){button.addEventListener('click',function(){document.getElementById('deleteRecordName').textContent=button.dataset.name||'Selected record';});});
    document.querySelectorAll('.activate-record').forEach(function(button){button.addEventListener('click',function(){alert('Activation placeholder: backend should enforce one active session and one active term in the active session.');});});
    document.querySelectorAll('.export-record').forEach(function(button){button.addEventListener('click',function(){alert(button.dataset.format+' export placeholder ready for backend integration.');});});
    document.querySelectorAll('.bulk-delete').forEach(function(button){button.addEventListener('click',function(){alert('Bulk delete placeholder. Future backend should soft-delete selected records with audit logs.');});});
    document.getElementById('academicEntityForm').addEventListener('submit',function(e){e.preventDefault();if(!this.checkValidity()){this.reportValidity();return;}alert('Record saved in placeholder mode. Future endpoint: '+this.action);});
    document.getElementById('deleteAcademicForm').addEventListener('submit',function(e){e.preventDefault();alert('Record deleted in placeholder mode. Future endpoint: '+this.action);});
})();
</script>
